public static int ClimbStairs(int n)
{
    if (n == 1)
    {
    return 1;
    }
    if (n == 2)
    {
    return 2;
    }
    int[] dp = new int[n + 1];
    dp[1] = 1;
    dp[2] = 2;
    for (int i = 3; i <= n; i++)
    {
    dp[i] = dp[i - 1] + dp[i - 2];
    }
    return dp[n];
}

public static int ClimbStairs(int n)
{
    // Base cases
    if (n == 1) return 1;
    if (n == 2) return 2;
    // Initialize variables to store the number of ways to climb
    int prev = 1;
    int curr = 2;
    // Calculate the number of ways to climb for n > 2
    for (int i = 3; i <= n; i++)
    {
    int temp = curr;
    curr = prev + curr;
    prev = temp;
    }
    return curr;
}
